{
  "title": "ग्राउंडिंग बनाम हैल्युसिनेशन",
  "group": "उन्नत",
  "options": [
    {
      "text": "सिस्टम प्रॉम्प्ट में मॉडल को बताएं कि 'हैल्युसिनेशन न करें'"
    },
    {
      "text": "अधिक आत्मविश्वासपूर्ण प्रतिक्रियाएं जनरेट करने के लिए उच्च temperature का उपयोग करें"
    },
    {
      "text": "पुनर्प्राप्त स्रोत दस्तावेज़ प्रदान करें और मॉडल को उन्हें संदर्भित (cite) करने का निर्देश दें"
    },
    {
      "text": "बड़ा मॉडल उपयोग करें — हैल्युसिनेशन केवल छोटे मॉडल में होता है"
    }
  ],
  "questionProse": [
    "प्रोडक्शन AI सिस्टम में हैल्युसिनेशन कम करने की सबसे प्रभावी तकनीक है:"
  ],
  "explanationProse": [
    "मॉडल को हैल्युसिनेशन न करने का निर्देश देने से वह रुकता नहीं है — मॉडल के पास यह पता लगाने का कोई विश्वसनीय आंतरिक संकेत नहीं होता कि 'मैं यह गढ़ रहा हूँ।' इसका मतलब बस इतना है कि मॉडल आत्मविश्वास से कह देगा कि वह कुछ नहीं गढ़ रहा, जबकि वह वास्तव में कुछ गढ़ ही रहा होगा।\n\n    असल में क्या काम करता है: **ग्राउंडिंग**। मॉडल को सही उत्तर देने के लिए आवश्यक जानकारी दें, और उसे उसी जानकारी तक सीमित रखें:",
    "फिर आउटपुट की सत्यापन करें: जांचें कि प्रतिक्रिया में दिए गए दावे पुनर्प्राप्त संदर्भ (retrieved context) में मौजूद हैं या नहीं। इसे साइटेशन ग्राउंडिंग चेक कहते हैं — कार्यान्वयन के लिए RAG इवैल चर्चा देखें।\n\n    बड़े मॉडल औसतन कम हैल्युसिनेट करते हैं, लेकिन सभी मॉडल हैल्युसिनेट करते हैं। ग्राउंडिंग ही निवारण रणनीति है, मॉडल का साइज़ नहीं।"
  ]
}
